import { Component, EventEmitter, Output, ChangeDetectionStrategy } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { UserRole } from '../../models/user.model';

@Component({
  selector: 'app-user-form',
  templateUrl: './user-form.component.html',
  styleUrls: ['./user-form.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class UserFormComponent {
  @Output() userAdded = new EventEmitter<{ name: string; email: string; role: UserRole }>();
  @Output() cancelled = new EventEmitter<void>();

  readonly roles: UserRole[] = ['Admin', 'Editor', 'Viewer'];
  submitted = false;
  isSubmitting = false;

  form: FormGroup;

  constructor(private fb: FormBuilder) {
    this.form = this.fb.group({
      name: [
        '',
        [
          Validators.required,
          Validators.minLength(2),
          Validators.maxLength(60),
          Validators.pattern(/^[a-zA-Z\s'-]+$/)
        ]
      ],
      email: [
        '',
        [
          Validators.required,
          Validators.email,
          Validators.maxLength(120)
        ]
      ],
      role: ['', Validators.required]
    });
  }

  get name()  { return this.form.get('name')!; }
  get email() { return this.form.get('email')!; }
  get role()  { return this.form.get('role')!; }

  getNameError(): string {
    if (this.name.hasError('required'))   return 'Name is required.';
    if (this.name.hasError('minlength'))  return 'Name must be at least 2 characters.';
    if (this.name.hasError('maxlength'))  return 'Name must not exceed 60 characters.';
    if (this.name.hasError('pattern'))    return 'Name may only contain letters, spaces, hyphens and apostrophes.';
    return '';
  }

  getEmailError(): string {
    if (this.email.hasError('required'))   return 'Email is required.';
    if (this.email.hasError('email'))      return 'Please enter a valid email address.';
    if (this.email.hasError('maxlength'))  return 'Email is too long.';
    return '';
  }

  async onSubmit(): Promise<void> {
    this.submitted = true;
    if (this.form.invalid) return;

    this.isSubmitting = true;
    // Simulate async save
    await new Promise(r => setTimeout(r, 400));

    this.userAdded.emit({
      name:  this.form.value.name,
      email: this.form.value.email,
      role:  this.form.value.role as UserRole
    });
    this.isSubmitting = false;
  }

  onCancel(): void {
    this.cancelled.emit();
  }
}
<div class="user-form-card">

  <div class="form-header">
    <div class="form-header__icon">
      <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2">
        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
        <circle cx="12" cy="7" r="4"/>
        <line x1="19" y1="8" x2="19" y2="14"/>
        <line x1="22" y1="11" x2="16" y2="11"/>
      </svg>
    </div>
    <div>
      <h2 class="form-header__title">Add New User</h2>
      <p class="form-header__sub">Fill in the details below to add a team member</p>
    </div>
    <button class="close-btn" type="button" (click)="onCancel()" aria-label="Close">
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
        <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
      </svg>
    </button>
  </div>

  <form [formGroup]="form" (ngSubmit)="onSubmit()" novalidate>

    <div class="field" [class.field--error]="submitted && name.invalid">
      <label class="field__label" for="name">Full Name <span class="required">*</span></label>
      <input
        id="name"
        type="text"
        class="field__input"
        placeholder="e.g. Jane Smith"
        formControlName="name"
        autocomplete="name"
      />
      <span class="field__error" *ngIf="submitted && name.invalid" role="alert">
        {{ getNameError() }}
      </span>
    </div>

    <div class="field" [class.field--error]="submitted && email.invalid">
      <label class="field__label" for="email">Email Address <span class="required">*</span></label>
      <input
        id="email"
        type="email"
        class="field__input"
        placeholder="e.g. jane@company.com"
        formControlName="email"
        autocomplete="email"
      />
      <span class="field__error" *ngIf="submitted && email.invalid" role="alert">
        {{ getEmailError() }}
      </span>
    </div>

    <div class="field" [class.field--error]="submitted && role.invalid">
      <label class="field__label" for="role">Role <span class="required">*</span></label>
      <div class="select-wrap">
        <select id="role" class="field__select" formControlName="role">
          <option value="" disabled selected>Select a role…</option>
          <option *ngFor="let r of roles" [value]="r">{{ r }}</option>
        </select>
        <svg class="select-arrow" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
          <polyline points="6 9 12 15 18 9"/>
        </svg>
      </div>
      <span class="field__error" *ngIf="submitted && role.invalid" role="alert">
        Please select a role.
      </span>

      <div class="role-chips" *ngIf="role.value">
        <span class="role-chip role-chip--admin"   *ngIf="role.value === 'Admin'">Full access to all features and settings</span>
        <span class="role-chip role-chip--editor"  *ngIf="role.value === 'Editor'">Can create and edit content</span>
        <span class="role-chip role-chip--viewer"  *ngIf="role.value === 'Viewer'">Read-only access</span>
      </div>
    </div>

    <div class="form-actions">
      <button type="button" class="btn btn--ghost" (click)="onCancel()" [disabled]="isSubmitting">
        Cancel
      </button>
      <button type="submit" class="btn btn--primary" [disabled]="isSubmitting">
        <span class="btn__spinner" *ngIf="isSubmitting"></span>
        <span *ngIf="!isSubmitting">
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"
               style="vertical-align:-2px;margin-right:6px">
            <polyline points="20 6 9 17 4 12"/>
          </svg>
          Add User
        </span>
      </button>
    </div>

  </form>
</div>
